await cms.first({
  type: DocsSchema,
  include: {
    parents: Query.parents({
      select: {
        url: Query.url, 
        title: Query.title
      }
    }),  
    children: Query.children({
      type: Doc, 
      select: {
        url: Query.url, 
        title: Query.title
      }
    }),
    siblings: Query.siblings({
      type: Docs, 
      select: {
        url: Query.url, 
        title: Query.title
      }
    })
  }
})

await cms.first({
  type: DocSchema,

  include: {   
    previous: Query.previous({
      select: {
        url: Query.url, 
        title: Query.title
      }
    }),
    next: Query.next({
      select: {
        url: Query.url, 
        title: Query.title
      }
    })
  }
})

await cms.first({
  type: DocSchema,

  include: {   
    translations: Query.translations({
      select: {locale: Query.locale, url: Query.url}
    })
  }
})
